SELECT setval(pg_get_serial_sequence('exams', 'id'), COALESCE((SELECT MAX(id) FROM exams), 1), true);
SELECT setval(pg_get_serial_sequence('topic_tables', 'id'), COALESCE((SELECT MAX(id) FROM topic_tables), 1), true);
SELECT setval(pg_get_serial_sequence('subtopics', 'id'), COALESCE((SELECT MAX(id) FROM subtopics), 1), true);
SELECT setval(pg_get_serial_sequence('timetable_items', 'id'), COALESCE((SELECT MAX(id) FROM timetable_items), 1), true);

COMMIT;
